#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const int a = 202020;
    const int b = 666;
    int result = a / b; // integer division
    while (T--) {
        printf("%d\n", result);
    }
    return 0;
}

